sql:
SELECT MAX(p_bid_price) AS max_bid_price
FROM stock_exchange_data
WHERE ticker = 'COST' AND curr_date = '10/8/2019';

SELECT ticker
FROM stock_exchange_data
WHERE data_status = 'active' AND p_volume > 1000;

SELECT AVG(p_implied_volatility) AS avg_implied_volatility
FROM stock_exchange_data
WHERE curr_date = '2019-10-08';

external_knowledge:
- COST is the stock ticker symbol for Costco Wholesale Corporation; 
- Implied volatility is a measure of the market's expected volatility of a stock's price in the near future; 
- Data reliability score is a measure used to evaluate the trustworthiness and accuracy of data.

sql:
SELECT company_name
FROM stock_tickers
WHERE sector = 'Technology';

SELECT AVG(p_bid_price) AS avg_bid_price, COUNT(*) AS data_points
  FROM stock_exchange_data
  WHERE ticker = 'COST';

SELECT ticker, AVG(p_bid_price) AS average_bid_price
FROM stock_exchange_data
GROUP BY ticker;
